    {
      "name": "Draft v1",
      "days": 7
    },
    {
      "name": "Revision + handoff",
      "days": 10
    }
  ],
  "acceptance_criteria": [
    "Answers the core question in plain language",
    "Lists assumptions and risks explicitly",
    "Includes next actions the client can execute"
  ],
  "proposal_spine": "You need clarity on \u00ab2-week climate-tech research sprint\u00bb. I will turn the fog into a claim lattice, a decision-ready memo, and a scoped next step\u2014so you can act without false certainty."
